# --- ROLES DEFINITION ---
role BaseEmployee { permissions = [login, view_directory] }

role MedicalStaff extends BaseEmployee { permissions = [view_schedules] }

role Nurse extends MedicalStaff { permissions = [update_vitals, view_patients] }

role Doctor extends MedicalStaff { permissions = [prescribe_meds, perform_surgery] }

role Specialist extends Doctor { permissions = [order_lab_tests] }

role PharmacyTech { permissions = [fill_prescriptions] }

role Pharmacist extends PharmacyTech { permissions = [verify_controlled_substances] }

role Intern extends MedicalStaff { permissions = [shadow_doctor] }

role OverprivilegedIntern extends MedicalStaff { permissions = [read_mri] }

# --- SECURITY POLICIES ---
mutex Doctor Pharmacist
mutex Nurse PharmacyTech

# --- USER ASSIGNMENTS ---
user Alice { roles = [Nurse] }

user Smith { roles = [Doctor] }

user Jones { roles = [Specialist] }

user UnknownUser { roles = [BaseEmployee] }

user Bob { roles = [Intern] }

user Charlie { roles = [OverprivilegedIntern] }

user Dave { roles = [Pharmacist] }
